<?php require __DIR__.'/includes/pawn_bootstrap.php';$id=(int)($_GET['id']??0);$st=$conn->prepare("SELECT pe.*,c.customer_name FROM pawn_entries pe JOIN customers c ON c.id=pe.customer_id WHERE pe.id=? AND pe.business_id=? AND pe.branch_id=? AND pe.status IN ('Active','Partially Paid')");$st->bind_param('iii',$id,$businessId,$branchId);$st->execute();$pawn=$st->get_result()->fetch_assoc();$st->close();if(!$pawn)die('Active pawn not found.');$st=$conn->prepare('SELECT id,method_name FROM payment_methods WHERE business_id=? AND is_active=1');$st->bind_param('i',$businessId);$st->execute();$methods=$st->get_result()->fetch_all(MYSQLI_ASSOC);$st->close();$theme=pawn_theme($conn,$businessId);?>
<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Pawn Release</title><?php include 'includes/links.php';include __DIR__.'/includes/pawn_styles.php';?></head><body><?php include 'includes/sidebar.php';?><main class="app-main"><?php include 'includes/nav.php';?><div class="content-wrap"><form class="pawn-card" id="form"><div class="pawn-head"><div><div class="pawn-title">Release Pawn</div><div class="small text-muted"><?=pawn_e($pawn['pawn_no'].' · '.$pawn['customer_name'])?></div></div><a href="pawn-view.php?id=<?=$id?>" class="btn btn-light btn-sm">Back</a></div><input type="hidden" name="csrf_token" value="<?=pawn_e($pawnCsrf)?>"><input type="hidden" name="pawn_entry_id" value="<?=$id?>"><div class="section"><div class="alert alert-warning">This action closes the pawn after collecting the outstanding principal and any final charges.</div><div class="row g-3"><div class="col-md-3"><label class="field-label">Release date</label><input type="date" class="form-control" name="payment_date" value="<?=date('Y-m-d')?>"></div><div class="col-md-3"><label class="field-label">Outstanding principal</label><input type="number" step="0.01" class="form-control calc" name="principal_amount" value="<?=pawn_e($pawn['balance_principal'])?>" readonly></div><div class="col-md-3"><label class="field-label">Final interest</label><input type="number" step="0.01" class="form-control calc" name="interest_amount" value="0"></div><div class="col-md-3"><label class="field-label">Penalty</label><input type="number" step="0.01" class="form-control calc" name="penalty_amount" value="0"></div><div class="col-md-3"><label class="field-label">Total</label><input type="number" step="0.01" class="form-control" name="total_amount" readonly></div><div class="col-md-3"><label class="field-label">Payment method</label><select class="form-select" name="payment_method_id"><option value="">Select</option><?php foreach($methods as $m):?><option value="<?=$m['id']?>"><?=pawn_e($m['method_name'])?></option><?php endforeach?></select></div></div></div><div class="section text-end"><button class="btn btn-theme">Confirm Release</button></div></form></div></main><?php include 'includes/script.php';?><script src="assets/js/script.js"></script><script>const f=document.getElementById('form');function c(){f.total_amount.value=([f.principal_amount,f.interest_amount,f.penalty_amount].reduce((a,x)=>a+(parseFloat(x.value)||0),0)).toFixed(2)}document.querySelectorAll('.calc').forEach(x=>x.oninput=c);c();f.onsubmit=async e=>{e.preventDefault();if(!confirm('Release this pawn?'))return;const x=await fetch('api/pawn-release-save.php',{method:'POST',body:new FormData(f)}),j=await x.json();alert(j.message);if(j.success)location.href='pawn-view.php?id=<?=$id?>'};</script></body></html>
